import common = require("oci-common");
/**
 * @example Click {@link https://docs.oracle.com/en-us/iaas/tools/typescript-sdk-examples/latest/aidp/ListSessions.ts.html |here} to see how to use ListSessionsRequest.
 */
export interface ListSessionsRequest extends common.BaseRequest {
    /**
     * The [OCID]({{DOC_SERVER_URL}}/iaas/Content/General/Concepts/identifiers.htm) of the AI Data Platform (Data Lake) instance.
     */
    'aiDataPlatformId': string;
    /**
     * The key of the Workspace
     */
    'workspaceKey': string;
    /**
     * Cluster ID attached to a session.
     */
    'clusterId'?: string;
    /**
     * Notebook file path attached to a session.
     */
    'path'?: string;
    /**
     * Unique Oracle-assigned identifier for the request. If you need to contact
    * Oracle about a particular request, please provide the request ID.
    * The only valid characters for request IDs are letters, numbers,
    * underscore, and dash.
    *
     */
    'opcRequestId'?: string;
    /**
     * Agent flow key of the attached agent flow.
     */
    'agentFlowKey'?: string;
}
